import AsyncStorage from '@react-native-async-storage/async-storage';
import {
  secureStorageSetItem,
  secureStorageGetItem,
  secureStorageRemoveItem,
  secureStorageMultiSet,
  secureStorageMultiGet,
} from './storageCrypto';

const KEYS = {
  USER_PROFILE: 'secure:user_profile',
  PAYMENT_INFO: 'secure:payment_info',
  AUTH_TOKEN: 'secure:auth_token',
};

export const SecureDataService = {
  keys: KEYS,

  saveUserProfile: async (profile) => {
    await secureStorageSetItem(AsyncStorage, KEYS.USER_PROFILE, profile);
  },

  getUserProfile: async () => {
    return secureStorageGetItem(AsyncStorage, KEYS.USER_PROFILE, true);
  },

  savePaymentInfo: async (paymentInfo) => {
    await secureStorageSetItem(AsyncStorage, KEYS.PAYMENT_INFO, paymentInfo);
  },

  getPaymentInfo: async () => {
    return secureStorageGetItem(AsyncStorage, KEYS.PAYMENT_INFO, true);
  },

  saveAuthToken: async (token) => {
    await secureStorageSetItem(AsyncStorage, KEYS.AUTH_TOKEN, token);
  },

  getAuthToken: async () => {
    return secureStorageGetItem(AsyncStorage, KEYS.AUTH_TOKEN, false);
  },

  clearAll: async () => {
    await Promise.all([
      secureStorageRemoveItem(AsyncStorage, KEYS.USER_PROFILE),
      secureStorageRemoveItem(AsyncStorage, KEYS.PAYMENT_INFO),
      secureStorageRemoveItem(AsyncStorage, KEYS.AUTH_TOKEN),
    ]);
  },

  saveAll: async ({ userProfile, paymentInfo, authToken }) => {
    const entries = [];
    if (userProfile !== undefined) entries.push([KEYS.USER_PROFILE, userProfile]);
    if (paymentInfo !== undefined) entries.push([KEYS.PAYMENT_INFO, paymentInfo]);
    if (authToken !== undefined) entries.push([KEYS.AUTH_TOKEN, authToken]);
    await secureStorageMultiSet(AsyncStorage, entries);
  },

  getAll: async () => {
    return secureStorageMultiGet(
      AsyncStorage,
      [KEYS.USER_PROFILE, KEYS.PAYMENT_INFO, KEYS.AUTH_TOKEN],
      [KEYS.USER_PROFILE, KEYS.PAYMENT_INFO]
    );
  },
};

